public static int[] readFromBinaryFile(String filename) throws IOException 
    {
        DataInputStream d = new DataInputStream(new FileInputStream(new File(filename))); 

        int[] x = null;
        int len = d.readInt();

        if (len>0)
        {
            x = new int[len];

            for (int i=0; i<len; i++)
                x[i] = d.readInt();
        }

        d.close();

        return x;
    }

