public synchronized void run () {
        LOGGER.log(Level.FINE, command);
        pes.fireHandleProgressEvent (tmId, new Status (ActionType.EXECUTE, cmdType, command /* message */, StateType.RUNNING));

        output = "";
        authorized = true;

        int retries = 4;

        // similar to Tomcat's Ant task
        URLConnection conn = null;
        InputStreamReader reader = null;

        URL urlToConnectTo = null;

        boolean failed = false;
        String msg = null;
        while (retries >= 0) {
            retries = retries - 1;
            try {

                // Create a connection for this command
                String uri = tm.getPlainUri ();
                String withoutSpaces = (uri + command).replace(" ", "%20");  //NOI18N
                urlToConnectTo = new URL(withoutSpaces);

                if (Boolean.getBoolean("org.netbeans.modules.tomcat5.LogManagerCommands")) { // NOI18N
                    String message = "Tomcat 5 sending manager command: " + urlToConnectTo;
                    Logger.getLogger(TomcatManagerImpl.class.getName()).log(Level.FINE, null, new Exception(message));
                }

                if (tm.isMisconfiguredProxy()) {
                    conn = urlToConnectTo.openConnection(Proxy.NO_PROXY);
                } else {
                    conn = urlToConnectTo.openConnection();
                }
                HttpURLConnection hconn = (HttpURLConnection) conn;

                // Set up standard connection characteristics
                hconn.setAllowUserInteraction(false);
                hconn.setDoInput(true);
                hconn.setUseCaches(false);
                if (istream != null) {
                    hconn.setDoOutput(true);
                    hconn.setRequestMethod("PUT");   // NOI18N
                    hconn.setRequestProperty("Content-Type", "application/octet-stream");   // NOI18N
                } else {
                    hconn.setDoOutput(false);
                    hconn.setRequestMethod("GET"); // NOI18N
                }
                hconn.setRequestProperty("User-Agent", // NOI18N
                                         "NetBeansIDE-Tomcat-Manager/1.0"); // NOI18N
                // Set up an authorization header with our credentials
                TomcatProperties tp = tm.getTomcatProperties();
                String input = tp.getUsername () + ":" + tp.getPassword ();
                String auth = Base64.getEncoder().encodeToString(input.getBytes());
                hconn.setRequestProperty("Authorization", // NOI18N
                                         "Basic " + auth); // NOI18N

                // Establish the connection with the server
                hconn.connect();
                int respCode = hconn.getResponseCode();
                if (respCode == HttpURLConnection.HTTP_UNAUTHORIZED 
                    || respCode == HttpURLConnection.HTTP_FORBIDDEN) {
                    // connection to tomcat manager has not been allowed
                    authorized = false;
                    String errMsg = NbBundle.getMessage(TomcatManagerImpl.class, "MSG_AuthorizationFailed");
                    pes.fireHandleProgressEvent (null, new Status (ActionType.EXECUTE, cmdType, errMsg, StateType.FAILED));
                    return;
                } else if (respCode == HttpURLConnection.HTTP_BAD_GATEWAY) {
                    throw new IOException(Integer.toString(respCode));
                }
                if (Boolean.getBoolean("org.netbeans.modules.tomcat5.LogManagerCommands")) { // NOI18N
                    int code = hconn.getResponseCode();
                    String message = "Tomcat 5 receiving response, code: " + code;
                    System.out.println(message);
                    Logger.getLogger(TomcatManagerImpl.class.getName()).log(Level.INFO, null, new Exception(message));
                }
                // Send the request data (if any)
                if (istream != null) {
                    BufferedOutputStream ostream =
                        new BufferedOutputStream(hconn.getOutputStream(), 1024);
                    byte buffer[] = new byte[1024];
                    while (true) {
                        int n = istream.read(buffer);
                        if (n < 0) {
                            break;
                        }
                        ostream.write(buffer, 0, n);
                    }
                    ostream.flush();
                    ostream.close();
                    istream.close();
                }

                // Process the response message
                reader = new InputStreamReader(hconn.getInputStream(), StandardCharsets.UTF_8);
                retries = -1;
                StringBuffer buff = new StringBuffer();
                String error = null;
                msg = null;
                boolean first = !command.startsWith ("jmxproxy");   // NOI18N
                while (true) {
                    int ch = reader.read();
                    if (ch < 0) {
                        output += buff.toString ()+"\n";    // NOI18N
                        break;
                    } else if ((ch == '\r') || (ch == '\n')) {
                        String line = buff.toString();
                        buff.setLength(0);
                        LOGGER.log(Level.FINE, line);
                        if (first) {
                            // hard fix to accept the japanese localization of manager app
                            String japaneseOK="\u6210\u529f"; //NOI18N
                            msg = line;
                            // see issue #62529
                            if (line.indexOf("java.lang.ThreadDeath") != -1) { // NOI18N
                                String warning = NbBundle.getMessage(TomcatManagerImpl.class, "MSG_ThreadDeathWarning");
                                pes.fireHandleProgressEvent(
                                    tmId, 
                                    new Status(ActionType.EXECUTE, cmdType, warning, StateType.RUNNING)
                                );
                            } else if (!(line.startsWith("OK -") || line.startsWith(japaneseOK))) { // NOI18N
                                error = line;
                            }
                            first = false;
                        }
                        output += line+"\n";    // NOI18N
                    } else {
                        buff.append((char) ch);
                    }
                }
                if (buff.length() > 0) {
                    LOGGER.log(Level.FINE, buff.toString());
                }
                if (error != null) {
                    LOGGER.log (Level.INFO, "TomcatManagerImpl connecting to: " + urlToConnectTo, error); // NOI18N
                    pes.fireHandleProgressEvent (tmId, new Status (ActionType.EXECUTE, cmdType, error, StateType.FAILED));
                    failed = true;
                }
                if (msg == null) {
                    msg = buff.toString();
                }
            } catch (Exception e) {
                if (e instanceof IOException && e.getMessage() != null
                        && e.getMessage().contains(Integer.toString(HttpURLConnection.HTTP_BAD_GATEWAY))) {
                    tm.setMisconfiguredProxy(true);
                    LOGGER.log(Level.INFO, "Proxy is misconfigured for localhost");
                } else if (tm.isMisconfiguredProxy()) {
                    tm.setMisconfiguredProxy(false);
                }
                if (retries < 0) {
                    LOGGER.log(Level.INFO, "TomcatManagerImpl connecting to: " + urlToConnectTo, e); // NOI18N
                    pes.fireHandleProgressEvent (tmId, new Status (ActionType.EXECUTE, cmdType, e.getLocalizedMessage (), StateType.FAILED));
                    failed = true;
                }
                // throw t;
            } finally {
                if (reader != null) {
                    try {
                        reader.close();
                    } catch (java.io.IOException ioe) { // ignore this
                    }
                    reader = null;
                }
                if (istream != null) {
                    try {
                        istream.close();
                    } catch (java.io.IOException ioe) { // ignore this
                    }
                    istream = null;
                }                
            }
            if (retries >=0) {
                try {
                    Thread.sleep(3000);
                } catch (InterruptedException e) {}
            }
        } // while
        if (!failed) {
            pes.fireHandleProgressEvent (tmId, new Status (ActionType.EXECUTE, cmdType, msg, StateType.COMPLETED));
        }
    }

private void processJarFile(Jar jar, File file, ApplicationModule module)
			throws IOException, CancelledException {
		if (!file.exists()) {
			return;
		}
		if (processedJars.contains(file)) {
			return;
		}
		processedJars.add(file);
		JarFile jarFile = new JarFile(file);
		Enumeration<JarEntry> entries = jarFile.entries();
		while (entries.hasMoreElements()) {
			JarEntry jarEntry = entries.nextElement();

			// Special case for Log4j:
			//
			//  	Log4j scatters .dat files around in modules that use the log4j
			//		plugin construct. Each one contains the plugins that that module
			//		requires. The problem is that each of these has the exact same path:
			//
			//		META-INF/org/apache/logging/log4j/core/config/plugins/Log4j2Plugins.dat
			//
			//		If we just blindly copy all of them to our new jar, we risk overwriting the
			//		.dat file from the log4j core library (which is the one we really need). To
			//		avoid this, the following code ensures that we only copy the one from the
			//		core jar.
			//
			//  	NOTE: The above statement obviously means that we're dropping the information
			//			contained in the 'other' .dat files. This could cause a problem at some
			//			point, even though it doesn't now. As such, we may want to try to merge
			//			all the .dat files together at some point.
			//
			if (jarEntry.getName().contains("Log4j2Plugins.dat")) {
				if (jarFile.getName().contains("log4j-core")) {
					jar.addJarEntry(jarFile, jarEntry, module);
				}
				else {
					continue;
				}
			}

			jar.addJarEntry(jarFile, jarEntry, module);
		}
	}

public void exportProject(HttpServletRequest request,
							  HttpServletResponse response) throws Exception {

		Permissions.ensureAdmin(Common.getUser(request));
		extractExportParametersFromRequest(request);

		response.setHeader("Content-Disposition", "attachment; filename="
				+ projectName.replaceAll(" ", "") + ".zip");

		List<FileToPack> tempFiles = new ArrayList<>();

		tempFiles.add(buildProjectDescriptionFile(projectName, projectDescription));
		tempFiles.add(buildJSONFile(JSON_FILE_NAME, includePointValues));

		List<FileToPack> filesToZip = new ArrayList<>();
		if (includeUploadsFolder)
			filesToZip.addAll(getUploadsFolderFiles());

		if (includeGraphicsFolder)
			filesToZip.addAll(getGraphicsFolderFiles());

		filesToZip.addAll(tempFiles);

		ServletOutputStream out = response.getOutputStream();
		FileUtil.compactFiles(out,
				filesToZip.toArray(new FileToPack[filesToZip.size()]));

		deleteFiles(tempFiles);
	}

public void addFile(String jarPath, File file, ApplicationModule module)
				throws IOException, CancelledException {
			if (!file.exists()) {
				throw new AssertException(
					"Attempted to write a file that does not exist to the jar! File = " +
						file.getAbsolutePath());
			}

			if (!file.isFile()) {
				throw new AssertException(
					"Attempted to write a directory to the jar! File = " + file.getAbsolutePath());
			}

			jarPath = jarPath.replaceAll("\\\\", "/"); // handle windows separators

			long modifiedTime = file.lastModified();
			addToModuleTree(jarPath, module);
			if (extensionPointSuffixPattern.matcher(jarPath).matches()) {
				checkExtensionPointClass(jarPath, new FileInputStream(file));
			}

			if (prefix != null) {
				jarPath = prefix + jarPath;
			}
			if (jarPath.contains("..")) {
				jarPath = Path.of(jarPath).normalize().toString();
			}

			ZipEntry entry = new ZipEntry(jarPath);
			entry.setTime(modifiedTime);

			try {
				jarOut.putNextEntry(entry);
			}
			catch (ZipException e) {
				System.out.println(e.getMessage());
				return;
			}

			InputStream in = new FileInputStream(file);

			byte[] bytes = new byte[4096];
			int numRead;

			while ((numRead = in.read(bytes)) != -1) {
				monitor.checkCanceled();
				jarOut.write(bytes, 0, numRead);
			}
			in.close();

			jarOut.closeEntry();

		}

@Override
    public AbstractPipelineOutput execute(final AbstractPipelineInput input) throws DITAOTException {
        if (logger == null) {
            throw new IllegalStateException("Logger not set");
        }
        try {
            final String baseDir = input.getAttribute(ANT_INVOKER_PARAM_BASEDIR);
            ditaDir=new File(input.getAttribute(ANT_INVOKER_EXT_PARAM_DITADIR));
            final String transtype = input.getAttribute(ANT_INVOKER_EXT_PARAM_TRANSTYPE);
            File ditavalFile = null;
            if (input.getAttribute(ANT_INVOKER_PARAM_DITAVAL) != null ) {
                ditavalFile = new File(input.getAttribute(ANT_INVOKER_PARAM_DITAVAL));
                if (!ditavalFile.isAbsolute()) {
                    ditavalFile = new File(baseDir, ditavalFile.getPath()).getAbsoluteFile();
                }

            }

            inputDir = new File(job.getInputDir());
            if (!inputDir.isAbsolute()) {
                inputDir = new File(baseDir, inputDir.getPath()).getAbsoluteFile();
            }
            inputMap = new File(inputDir, job.getInputMap()).getAbsoluteFile();

            // Output subject schemas
            outputSubjectScheme();
            final DitaValReader filterReader = new DitaValReader();
            filterReader.setLogger(logger);
            filterReader.initXMLReader("yes".equals(input.getAttribute(ANT_INVOKER_EXT_PARAN_SETSYSTEMID)));

            FilterUtils filterUtils = new FilterUtils(printTranstype.contains(transtype));
            filterUtils.setLogger(logger);
            if (ditavalFile != null){
                filterReader.read(ditavalFile.getAbsoluteFile());
                filterUtils.setFilterMap(filterReader.getFilterMap());
            }
            final SubjectSchemeReader subjectSchemeReader = new SubjectSchemeReader();
            subjectSchemeReader.setLogger(logger);

            final DitaWriter fileWriter = new DitaWriter();
            fileWriter.setLogger(logger);
            try{
                final boolean xmlValidate = Boolean.valueOf(input.getAttribute("validate"));
                fileWriter.initXMLReader(ditaDir.getAbsoluteFile(),xmlValidate, setSystemid);
            } catch (final SAXException e) {
                throw new DITAOTException(e.getMessage(), e);
            }
            fileWriter.setTempDir(job.tempDir);
            fileWriter.setTranstype(transtype);
            if (filterUtils != null) {
            	fileWriter.setFilterUtils(filterUtils);
            }
            fileWriter.setDelayConrefUtils(new DelayConrefUtils());
            fileWriter.setKeyDefinitions(KeyDef.readKeydef(new File(job.tempDir, KEYDEF_LIST_FILE)));

            job.setGeneratecopyouter(input.getAttribute(ANT_INVOKER_EXT_PARAM_GENERATECOPYOUTTER));
            job.setOutterControl(input.getAttribute(ANT_INVOKER_EXT_PARAM_OUTTERCONTROL));
            job.setOnlyTopicInMap(input.getAttribute(ANT_INVOKER_EXT_PARAM_ONLYTOPICINMAP));
            job.setInputFile(inputMap);
            job.setOutputDir(new File(input.getAttribute(ANT_INVOKER_EXT_PARAM_OUTPUTDIR)));
            fileWriter.setJob(job);

            final Map<String, Set<String>> dic = readMapFromXML(FILE_NAME_SUBJECT_DICTIONARY);

            for (final FileInfo f: job.getFileInfo()) {
                if ((f.isActive && ("dita".equals(f.format) || "ditamap".equals(f.format)))
                        || f.isConrefTarget || f.isCopyToSource) {
                    final File filename = f.file;
                    final File currentFile = new File(inputDir, filename.getPath());
                    logger.logInfo("Processing " + currentFile.getAbsolutePath());

                    final Set<String> schemaSet = dic.get(filename.getPath());
                    filterReader.reset();
                    if (schemaSet != null) {
                        subjectSchemeReader.reset();
                        final FilterUtils fu = new FilterUtils(printTranstype.contains(transtype));
                        fu.setLogger(logger);
                        for (final String schema: schemaSet) {
                            subjectSchemeReader.loadSubjectScheme(FileUtils.resolveFile(job.tempDir.getAbsolutePath(), schema) + SUBJECT_SCHEME_EXTENSION);
                        }
                        if (ditavalFile != null){
                            filterReader.filterReset();
                            filterReader.setSubjectScheme(subjectSchemeReader.getSubjectSchemeMap());
                            filterReader.read(ditavalFile.getAbsoluteFile());
                            final Map<FilterKey, Action> fm = new HashMap<FilterKey, Action>();
                            fm.putAll(filterReader.getFilterMap());
                            fm.putAll(filterUtils.getFilterMap());
                            fu.setFilterMap(Collections.unmodifiableMap(fm));
                        } else {
                            fu.setFilterMap(Collections.EMPTY_MAP);
                        }
                        fileWriter.setFilterUtils(fu);

                        fileWriter.setValidateMap(subjectSchemeReader.getValidValuesMap());
                        fileWriter.setDefaultValueMap(subjectSchemeReader.getDefaultValueMap());
                    } else {
                        fileWriter.setFilterUtils(filterUtils);
                    }

                    if (!currentFile.exists()) {
                        // This is an copy-to target file, ignore it
                        logger.logInfo("Ignoring a copy-to file " + filename);
                        continue;
                    }

                    fileWriter.write(inputDir, filename);
                }
            }

            // reload the property for processing of copy-to
            performCopytoTask(job.tempDir, job);
        } catch (final Exception e) {
            e.printStackTrace();
            throw new DITAOTException("Exception doing debug and filter module processing: " + e.getMessage(), e);
        }

        return null;
    }

private void restoreFiles(List<ZipEntry> uploadFiles) {
		String appPath = Common.ctx.getServletContext().getRealPath(
				FILE_SEPARATOR);

		byte[] buf = new byte[1024];
		try {
			for (ZipEntry zipEntry : uploadFiles) {
				InputStream zipinputstream;

				zipinputstream = this.zipFile.getInputStream(zipEntry);

				String entryName = zipEntry.getName();

				int n;

				String fileName = zipEntry.getName();

				File f = new File(appPath + fileName);

				File newFile = new File(entryName);

				String directory = newFile.getParent();

				if (directory != null) {
					if (newFile.isDirectory()) {
						break;
					}
					File dirFile = new File(appPath + directory);
					dirFile.mkdir();
				}

				FileOutputStream out = new FileOutputStream(f);

				while ((n = zipinputstream.read(buf, 0, 1024)) > -1)
					out.write(buf, 0, n);

				out.close();
				zipinputstream.close();
			}

		} catch (Exception e) {
			LOG.error(e.getMessage(), e);
		}
	}

