public static long getLength(Context context, Uri media) throws IOException {
        AssetFileDescriptor stat = null;
        long length = 0;
        try {
            stat = context.getContentResolver().openAssetFileDescriptor(media, "r");
            if (stat != null)
                length = stat.getLength();
        }
        finally {
            try {
                if (stat != null)
                    stat.close();
            }
            catch (IOException e) {
                // ignored
            }
        }

        if (length == 0) {
            // try to count bytes by reading it
            InputStream in = null;
            try {
                in = context.getContentResolver().openInputStream(media);
                CountingInputStream counter = new CountingInputStream(in);
                counter.consume();
                length = counter.getByteCount();
            }
            finally {
                try {
                    if (in != null)
                        in.close();
                }
                catch (IOException e) {
                    // ignored
                }
            }
        }

        return length;
    }

private void readObject(ObjectInputStream in)
            throws IOException, ClassNotFoundException {
        // read values
        in.defaultReadObject();

        // PAYARA-953 protect against null byte attacks 
        if (repository != null) {
            if (repository.getPath().contains("\0")) {
                throw new IOException("Repository path cannot contain a null byte");
            }

            if (!repository.isDirectory()) {
                throw new IOException("Repository path " + repository.getPath() + " is not a directory ");
            }
        }

        if (dfosFile != null) {
            if (dfosFile.getPath().contains("\0")) {
                throw new IOException("File path cannot contain a null byte");
            }
        }
        // END PAYARA-953

        OutputStream output = getOutputStream();
        if (cachedContent != null) {
            output.write(cachedContent);
        } else {
            FileInputStream input = new FileInputStream(dfosFile);
            Streams.copy(input, output, false);
            deleteFile(dfosFile);
            dfosFile = null;
        }
        output.close();

        cachedContent = null;
    }

